# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
from flask import Flask, request, jsonify, send_from_directory, abort

app = Flask(__name__)

# Configuration
# This is the base directory where all user files will be stored.
# In a real application, this might be dynamically determined per user
# or come from environment variables.
# For this example, we'll use a 'user_files' subdirectory in the current working directory.
USER_FILES_ROOT = os.path.join(os.getcwd(), "user_files")

# Ensure the root directory exists
os.makedirs(USER_FILES_ROOT, exist_ok=True)

def get_safe_path(user_relative_path):
    """
    Constructs a full, normalized, and safe path within the USER_FILES_ROOT.
    Prevents directory traversal attacks.
    """
    if not isinstance(user_relative_path, str):
        user_relative_path = "" # Treat non-string as empty path for safety

    # Construct the full path
    full_path = os.path.join(USER_FILES_ROOT, user_relative_path)

    # Normalize the path to handle '..' and clean up
    normalized_path = os.path.normpath(full_path)

    # Security check: Ensure the normalized path is still within the USER_FILES_ROOT
    # This is crucial to prevent directory traversal attacks.
    if not normalized_path.startswith(USER_FILES_ROOT):
        # If it tries to escape the root, default to the root itself or raise an error
        # Raising an error is generally safer.
        raise ValueError("Attempted directory traversal detected.")

    return normalized_path

@app.errorhandler(ValueError)
def handle_value_error(error):
    response = jsonify({'error': str(error)})
    response.status_code = 400 # Bad Request
    return response

@app.route('/list', methods=['GET'])
def list_directory():
    """
    Lists the contents of a directory.
    Query parameter: path (relative path from user's root)
    """
    user_path = request.args.get('path', '') # Default to root if no path is provided

    try:
        target_path = get_safe_path(user_path)
    except ValueError as e:
        return handle_value_error(e)

    if not os.path.isdir(target_path):
        abort(404, description=f"Directory not found or path is not a directory: {user_path}")

    try:
        contents = []
        with os.scandir(target_path) as entries:
            for entry in entries:
                contents.append({
                    'name': entry.name,
                    'type': 'directory' if entry.is_dir() else 'file',
                    'size': entry.stat().st_size if entry.is_file() else None,
                    'last_modified': entry.stat().st_mtime
                })
        return jsonify(contents)
    except PermissionError:
        abort(403, description="Permission denied to access this directory.")
    except Exception as e:
        app.logger.error(f"Error listing directory {target_path}: {e}")
        abort(500, description="An unexpected error occurred.")


@app.route('/download', methods=['GET'])
def download_file():
    """
    Downloads a specified file.
    Query parameter: path (relative path from user's root)
    """
    user_path = request.args.get('path')
    if not user_path:
        abort(400, description="Missing 'path' parameter.")

    try:
        full_file_path = get_safe_path(user_path)
    except ValueError as e:
        return handle_value_error(e)

    if not os.path.isfile(full_file_path):
        abort(404, description=f"File not found: {user_path}")

    try:
        # Use send_from_directory to safely serve files
        # It handles setting appropriate headers, chunking, etc.
        # It also implicitly performs a path validation to ensure
        # the file is within the base directory provided.
        # However, our get_safe_path provides an explicit check upfront.
        directory, filename = os.path.split(full_file_path)
        return send_from_directory(directory, filename, as_attachment=True)
    except PermissionError:
        abort(403, description="Permission denied to access this file.")
    except Exception as e:
        app.logger.error(f"Error downloading file {full_file_path}: {e}")
        abort(500, description="An unexpected error occurred during download.")


@app.route('/info', methods=['GET'])
def get_file_info():
    """
    Gets detailed information about a file or directory.
    Query parameter: path (relative path from user's root)
    """
    user_path = request.args.get('path')
    if not user_path:
        abort(400, description="Missing 'path' parameter.")

    try:
        target_path = get_safe_path(user_path)
    except ValueError as e:
        return handle_value_error(e)

    if not os.path.exists(target_path):
        abort(404, description=f"Path not found: {user_path}")

    try:
        stat_info = os.stat(target_path)
        is_dir = os.path.isdir(target_path)
        is_file = os.path.isfile(target_path)

        info = {
            'name': os.path.basename(target_path),
            'path': user_path, # Return the user's relative path
            'type': 'directory' if is_dir else 'file' if is_file else 'other',
            'exists': True,
            'size': stat_info.st_size if is_file else None,
            'creation_time': stat_info.st_ctime,
            'last_modified_time': stat_info.st_mtime,
            'last_access_time': stat_info.st_atime,
            'is_directory': is_dir,
            'is_file': is_file,
        }
        return jsonify(info)
    except PermissionError:
        abort(403, description="Permission denied to access this path.")
    except Exception as e:
        app.logger.error(f"Error getting info for {target_path}: {e}")
        abort(500, description="An unexpected error occurred.")


